// ─── Rutas de Firestore ancladas al club (multi-cliente) ─────────────
// Todo documento vive bajo clubes/{CLUB_ID}/{coleccion}/{id}.
// Así un club NUNCA puede leer accidentalmente los datos de otro: la ruta lo impide.
function coleccionClub(nombre) {
  return collection(db, "clubes", CLUB_ID, nombre);
}
function docClub(nombre, id) {
  return doc(db, "clubes", CLUB_ID, nombre, id);
}

// ─── Firestore hook genérico ─────────────────────────────────────────
function useColeccion(nombre, ordenarPor = "creadoEn", dir = "desc") {
  const [datos, setDatos] = useState([]);
  const [cargando, setCargando] = useState(true);

  useEffect(() => {
    const q = query(coleccionClub(nombre), orderBy(ordenarPor, dir));
    const unsub = onSnapshot(q, (snap) => {
      setDatos(snap.docs.map((d) => ({ ...d.data(), id: d.id })));
      setCargando(false);
    }, (err) => {
      console.error(`Error leyendo ${nombre}:`, err);
      setCargando(false);
    });
    return () => unsub();
  }, [nombre, ordenarPor, dir]);

  return { datos, cargando };
}

async function crearDoc(coleccion, data) {
  return addDoc(coleccionClub(coleccion), { ...data, creadoEn: serverTimestamp() });
}
async function actualizarDoc(coleccion, id, data) {
  return updateDoc(docClub(coleccion, id), data);
}
async function borrarDoc(coleccion, id) {
  return deleteDoc(docClub(coleccion, id));
}

const ROLES_PERMITIDOS_MANTENIMIENTO = ["jardinero", "greenkeeper", "mantenimiento", "superadmin"];
// ─── Autenticación (mismo contrato que Golf B Máster/Proshop) ────────
// Colección "Usuarios" en la raíz de Firestore (NO dentro de clubes/),
// documento indexado por UID de Firebase Auth, con un campo "role".
// IMPORTANTE: hasta ahora Mantenimiento se autenticaba solo, en
// silencio, con un token de club genérico (mintTenantToken) sin pedir
// ni email ni contraseña — cualquiera que abriera la URL, o cualquier
// sesión de otra app de Golf B ya abierta, entraba directamente sin
// comprobar quién era. Sustituido por login real + rol, igual que
// Proshop y Máster.
// Crea una cuenta de email/contraseña para un empleado usando una
// instancia de Firebase SECUNDARIA — así el superadmin que está
// creando el acceso no se queda desconectado de su propia sesión.
async function crearCuentaSinDesconectar(email, password) {
  const secundaria = initializeApp(firebaseConfig, `alta-${Date.now()}`);
  const authSecundaria = getAuth(secundaria);
  try {
    const cred = await createUserWithEmailAndPassword(authSecundaria, email, password);
    return cred.user.uid;
  } finally {
    await signOut(authSecundaria).catch(() => {});
    await deleteApp(secundaria).catch(() => {});
  }
}
function docUsuario(uid) { return doc(db, "Usuarios", uid); }

function useAuthMantenimiento() {
  const [currentUser, setCurrentUser] = useState(null);
  const [userRole, setUserRole] = useState(null);
  const [modulosActivos, setModulosActivos] = useState(null);
  const [cargandoAuth, setCargandoAuth] = useState(true);
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);
      if (user) {
        try {
          const snap = await getDoc(docUsuario(user.uid));
          setUserRole(snap.exists() ? (snap.data().role || "pendiente") : "pendiente");
        } catch (err) {
          console.error("Error al cargar rol:", err);
          setUserRole("pendiente");
        }
        try {
          const clubSnap = await getDoc(doc(db, "clubes", CLUB_ID));
          setModulosActivos(clubSnap.exists() && clubSnap.data().modulosActivos ? clubSnap.data().modulosActivos : null);
        } catch (err) {
          console.error("Error al cargar modulos activos del club:", err);
          setModulosActivos(null);
        }
      } else {
        setUserRole(null);
        setModulosActivos(null);
      }
      setCargandoAuth(false);
    });
    return unsub;
  }, []);
  return { currentUser, userRole, modulosActivos, cargandoAuth };
}

const inputLoginCls = "w-full px-3.5 py-2.5 rounded-xl bg-white/10 text-white text-sm border border-white/15 focus:outline-none focus:border-[#C6A253] placeholder-white/30 transition-colors";

function LoginMantenimiento() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [cargando, setCargando] = useState(false);
  const [mostrarReset, setMostrarReset] = useState(false);
  const [resetEnviado, setResetEnviado] = useState(false);

  async function entrar(e) {
    e.preventDefault();
    setError(""); setCargando(true);
    try { await signInWithEmailAndPassword(auth, email, password); }
    catch { setError("Email o contraseña incorrectos."); }
    setCargando(false);
  }
  async function recuperar(e) {
    e.preventDefault();
    setError(""); setCargando(true);
    try { await sendPasswordResetEmail(auth, email); setResetEnviado(true); }
    catch { setError("No se pudo enviar el email. Revisa la dirección."); }
    setCargando(false);
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: FONDO_APP }}>
      <div className="w-full max-w-sm">
        <div className="text-center mb-7">
          <div className="flex items-center justify-center gap-3">
            <img src={LOGO_GOLFB_VERDE} alt="Golf B" style={{ height: 44, objectFit: "contain" }} />
            <div className="w-px h-8" style={{ background: DORADO_SUAVE }} />
            <img src={LOGO_GCR} alt="Golf Ciudad Real" style={{ height: 44, objectFit: "contain", borderRadius: 6 }} />
          </div>
          <p className="text-sm mt-3" style={{ color: BLANCO_SUAVE }}>Mantenimiento · Golf Ciudad Real</p>
        </div>
        <div className="rounded-2xl p-7" style={{ background: VERDE_TARJETA, border: `1px solid ${DORADO_SUAVE}` }}>
          {!mostrarReset ? (
            <form onSubmit={entrar} className="space-y-4">
              <div>
                <label className="block text-xs font-medium mb-1.5" style={{ color: BLANCO_SUAVE }}>Email</label>
                <input type="email" required autoFocus value={email} onChange={(e) => setEmail(e.target.value)} className={inputLoginCls} placeholder="tu@email.com" />
              </div>
              <div>
                <label className="block text-xs font-medium mb-1.5" style={{ color: BLANCO_SUAVE }}>Contraseña</label>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className={inputLoginCls} placeholder="••••••••" />
              </div>
              {error && <p className="text-red-300 text-xs bg-red-900/25 rounded-lg px-3 py-2">{error}</p>}
              <button type="submit" disabled={cargando} className="w-full font-semibold py-2.5 rounded-xl text-sm transition disabled:opacity-50" style={{ background: DORADO, color: VERDE_NEGRO }}>
                {cargando ? "Entrando…" : "Entrar"}
              </button>
              <button type="button" onClick={() => { setMostrarReset(true); setError(""); }} className="w-full text-xs hover:text-white transition" style={{ color: BLANCO_TENUE }}>
                ¿Olvidaste tu contraseña?
              </button>
            </form>
          ) : (
            <div className="space-y-4">
              {resetEnviado ? (
                <p className="text-emerald-300 text-sm bg-emerald-900/20 rounded-lg px-3 py-3">Te hemos enviado un email con instrucciones para recuperar tu contraseña.</p>
              ) : (
                <form onSubmit={recuperar} className="space-y-4">
                  <p className="text-xs" style={{ color: BLANCO_SUAVE }}>Introduce tu email y te enviaremos un enlace para restablecer tu contraseña.</p>
                  <input type="email" required autoFocus value={email} onChange={(e) => setEmail(e.target.value)} className={inputLoginCls} placeholder="tu@email.com" />
                  {error && <p className="text-red-300 text-xs bg-red-900/25 rounded-lg px-3 py-2">{error}</p>}
                  <button type="submit" disabled={cargando} className="w-full font-semibold py-2.5 rounded-xl text-sm transition disabled:opacity-50" style={{ background: DORADO, color: VERDE_NEGRO }}>
                    {cargando ? "Enviando…" : "Enviar enlace"}
                  </button>
                </form>
              )}
              <button type="button" onClick={() => { setMostrarReset(false); setResetEnviado(false); setError(""); }} className="w-full text-xs hover:text-white transition" style={{ color: BLANCO_TENUE }}>
                ← Volver al login
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

