// FICHAJES + INFORMES
// ═══════════════════════════════════════════════════════════════════
function useCategoriasTarea() {
  const [categorias, setCategorias] = useState(null);
  useEffect(() => {
    const unsub = onSnapshot(docClub("mant_config", "categoriasTarea"), (snap) => {
      setCategorias(snap.exists() && snap.data().lista ? snap.data().lista : CATEGORIAS_TAREA_PREDEFINIDA);
    }, () => setCategorias(CATEGORIAS_TAREA_PREDEFINIDA));
    return () => unsub();
  }, []);
  async function guardar(nuevaLista) {
    await setDoc(docClub("mant_config", "categoriasTarea"), { lista: nuevaLista });
  }
  return { categorias: categorias || CATEGORIAS_TAREA_PREDEFINIDA, guardar };
}

